  1→import * as fs from 'fs';
  2→import * as path from 'path';
  3→import chalk from 'chalk';
  4→import ora from 'ora';
  5→import { loadSyncState, saveSyncState } from '../utils/config.js';
  6→import { trackEvent, identifyUser, captureError, classifyError } from '../utils/telemetry.js';
  7→import { insertSessionWithProjectAndReturnIsNew, insertMessages, recalculateUsageStats } from '../db/write.js';
  8→import { getDb, getMigrationResult } from '../db/client.js';
  9→import { getAllProviders, getProvider } from '../providers/registry.js';
 10→import { setProviderVerbose } from '../providers/context.js';
 11→import type { SessionProvider } from '../providers/types.js';
 12→import type { SyncState } from '../types.js';
 13→import { splitVirtualPath } from '../utils/paths.js';
 14→
 15→interface SyncOptions {
 16→  force?: boolean;
 17→  project?: string;
 18→  dryRun?: boolean;
 19→  quiet?: boolean;
 20→  verbose?: boolean;
 21→  regenerateTitles?: boolean;
 22→  source?: string;
 23→}
 24→
 25→export interface SyncResult {
 26→  syncedCount: number;
 27→  messageCount: number;
 28→  errorCount: number;
 29→  updatedExistingCount: number;
 30→  sessionsByProvider: Record<string, number>;
 31→}
 32→
 33→/**
 34→ * Core sync logic — reusable from stats commands and other callers.
 35→ *
 36→ * Parses sessions from all configured providers and writes to local SQLite.
 37→ * Throws on fatal errors (unknown provider) instead of calling process.exit().
 38→ * Returns a SyncResult summary.
 39→ */
 40→export async function runSync(options: SyncOptions = {}): Promise<SyncResult> {
 41→  const log = options.quiet ? () => {} : console.log.bind(console);
 42→  const noopSpinner = {
 43→    start: function() { return this; },
 44→    succeed: function() { return this; },
 45→    fail: function() { return this; },
 46→    warn: function() { return this; },
 47→    info: function() { return this; },
 48→    stop: function() { return this; },
 49→  };
 50→  const createSpinner = options.quiet
 51→    ? () => noopSpinner
 52→    : ora;
 53→
 54→  log(chalk.cyan('\n  Code Insights Sync\n'));
 55→
 56→  // Initialize database (runs migrations if needed)
 57→  const spinner = createSpinner('Initializing database...').start();
 58→  try {
 59→    getDb();
 60→    spinner.succeed('Database ready');
 61→  } catch (error) {
 62→    spinner.fail('Failed to initialize database');
 63→    throw new Error(`Database error: ${error instanceof Error ? error.message : 'Unknown error'}`);
 64→  }
 65→
 66→  // Check if V6 migration was just applied — triggers auto force-sync for interactive sessions
 67→  const migrationResult = getMigrationResult();
 68→  const v6JustApplied = migrationResult?.v6Applied === true;
 69→
 70→  if (v6JustApplied && options.quiet) {
 71→    // Hook-triggered sync: defer re-parse to avoid adding 30-60s to a sub-second operation
 72→    process.stderr.write("Message counts updated in v6. Run 'code-insights sync --force' to recalculate.\n");
 73→  }
 74→
 75→  // Auto force-sync on V6 migration (interactive only, not quiet/hook mode)
 76→  if (v6JustApplied && !options.quiet && !options.force && !options.dryRun) {
 77→    log(chalk.cyan('\n  V6 migration: recalculating message counts across all sessions...'));
 78→    log(chalk.dim('  Fixed: user messages were previously overcounted by including tool results and system messages'));
 79→    // Trigger force re-parse by treating this as a force sync for state reset
 80→    options = { ...options, force: true };
 81→  }
 82→
 83→  // Dry-run banner
 84→  if (options.dryRun) {
 85→    log(chalk.yellow('\n  Dry run -- no changes will be made'));
 86→  }
 87→
 88→  // Set verbose flag for providers (e.g., gates Cursor diagnostic warnings)
 89→  setProviderVerbose(!!options.verbose);
 90→
 91→  // Get providers to sync
 92→  let providers: SessionProvider[];
 93→  if (options.source) {
 94→    try {
 95→      providers = [getProvider(options.source)];
 96→    } catch {
 97→      throw new Error(`Unknown source: ${options.source}. Available: ${getAllProviders().map(p => p.getProviderName()).join(', ')}`);
 98→    }
 99→  } else {
100→    providers = getAllProviders();
101→  }
102→
103→  // Load sync state
104→  // When --force is used with --source, only clear the targeted provider's entries
105→  // instead of nuking the entire sync state.
106→  const syncState = loadSyncState();
107→  if (options.force) {
108→    if (options.source) {
109→      // Targeted force: remove only entries belonging to the specified provider's files
110→      const targetProviderPaths = new Set<string>();
111→      for (const provider of providers) {
112→        const discovered = await provider.discover({ projectFilter: options.project });
113→        for (const p of discovered) {
114→          const { realPath } = splitVirtualPath(p);
115→          targetProviderPaths.add(realPath);
116→        }
117→      }
118→      for (const key of Object.keys(syncState.files)) {
119→        if (targetProviderPaths.has(key)) {
120→          delete syncState.files[key];
121→        }
122→      }
123→    } else {
124→      // Full force: reset everything
125→      syncState.files = {};
126→    }
127→  }
128→
129→  let totalSyncedCount = 0;
130→  let totalMessageCount = 0;
131→  let totalErrorCount = 0;
132→  let totalUpdatedExisting = 0;
133→  const sessionsByProvider: Record<string, number> = {};
134→
135→  for (const provider of providers) {
136→    const providerName = provider.getProviderName();
137→    try {
138→      if (providers.length > 1) {
139→        log(chalk.cyan(`\n  Syncing ${providerName}...`));
140→      }
141→
142→      // Discovery
143→      spinner.start(`Discovering ${providerName} sessions...`);
144→      const sessionFiles = await provider.discover({ projectFilter: options.project });
145→      spinner.succeed(`Found ${sessionFiles.length} ${providerName} session files`);
146→
147→      if (sessionFiles.length === 0) continue;
148→
149→      // Filter to only new/modified files
150→      const filesToSync = filterFilesToSync(sessionFiles, syncState, options.force);
151→      log(chalk.gray(`  ${filesToSync.length} files need syncing (${sessionFiles.length - filesToSync.length} already synced)`));
152→
153→      if (filesToSync.length === 0) continue;
154→
155→      if (options.dryRun) {
156→        for (const file of filesToSync) {
157→          log(chalk.gray(`  Would sync: ${path.basename(file)}`));
158→        }
159→        continue;
160→      }
161→
162→      // Process files — accumulate per-provider counts, show one summary line after
163→      let providerSyncedCount = 0;
164→      let providerUpdatedCount = 0;
165→      let providerSkippedCount = 0;
166→      let providerMessageCount = 0;
167→
168→      for (const filePath of filesToSync) {
169→        const fileName = path.basename(filePath);
170→        spinner.start(`Processing ${fileName}...`);
171→
172→        try {
173→          // Parse session
174→          const session = await provider.parse(filePath);
175→          if (!session) {
176→            providerSkippedCount++;
177→            continue;
178→          }
179→
180→          // Skip trivial sessions (≤2 messages) — likely abandoned prompts with no content
181→          if (session.messageCount <= 2) {
182→            providerSkippedCount++;
183→            updateSyncState(syncState, filePath, session.id);
184→            saveSyncState(syncState);
185→            continue;
186→          }
187→
188→          // Write session and messages to SQLite
189→          const isNew = insertSessionWithProjectAndReturnIsNew(session, !!options.force);
190→          insertMessages(session);
191→
192→          // Update and persist sync state after each file
193→          // so progress survives crashes
194→          updateSyncState(syncState, filePath, session.id);
195→          saveSyncState(syncState);
196→
197→          if (!isNew && !options.force) {
198→            providerUpdatedCount++;
199→            totalUpdatedExisting++;
200→          }
201→
202→          providerSyncedCount++;
203→          providerMessageCount += session.messages.length;
204→          totalSyncedCount++;
205→          totalMessageCount += session.messages.length;
206→        } catch (error) {
207→          totalErrorCount++;
208→          spinner.fail(`Failed to sync ${fileName}`);
209→          if (!options.quiet) {
210→            console.error(chalk.red(`  ${error instanceof Error ? error.message : 'Unknown error'}`));
211→          }
212→        }
213→      }
214→
215→      sessionsByProvider[providerName] = providerSyncedCount;
216→
217→      // One summary line per provider instead of per-file noise
218→      spinner.stop();
219→      if (providerSyncedCount > 0 || providerSkippedCount > 0) {
220→        const providerNewCount = providerSyncedCount - providerUpdatedCount;
221→        const parts: string[] = [];
222→        if (providerNewCount > 0) parts.push(`${providerNewCount} new`);
223→        if (providerUpdatedCount > 0) parts.push(`${providerUpdatedCount} updated`);
224→        if (parts.length === 0) parts.push('0 synced');
225→        const syncedPart = `${parts.join(', ')}${providerMessageCount > 0 ? ` (${providerMessageCount.toLocaleString()} messages)` : ''}`;
226→        const skippedPart = providerSkippedCount > 0
227→          ? `, ${providerSkippedCount} empty`
228→          : '';
229→        log(chalk.gray(`  ${syncedPart}${skippedPart}`));
230→      }
231→    } catch (error) {
232→      totalErrorCount++;
233→      spinner.fail(`Failed to sync ${providerName}`);
234→      if (!options.quiet) {
235→        console.error(chalk.red(`  ${error instanceof Error ? error.message : 'Unknown error'}`));
236→      }
237→    }
238→  }
239→
240→  // Resurrect soft-deleted sessions on --force so users get a clean slate
241→  if (options.force) {
242→    const db = getDb();
243→    db.prepare('UPDATE sessions SET deleted_at = NULL WHERE deleted_at IS NOT NULL').run();
244→  }
245→
246→  // Reconcile usage stats after force sync (skip if nothing changed)
247→  const shouldRecalculateUsageStats = options.force
248→    ? (totalSyncedCount > 0 || totalErrorCount > 0)
249→    : totalUpdatedExisting > 0;
250→
251→  if (shouldRecalculateUsageStats) {
252→    spinner.start('Recalculating usage stats...');
253→    try {
254→      const result = recalculateUsageStats();
255→      spinner.succeed(`Usage stats reconciled (${result.sessionsWithUsage} sessions with usage data)`);
256→    } catch (error) {
257→      spinner.warn('Could not reconcile usage stats');
258→      if (!options.quiet) {
259→        console.error(chalk.red(`  ${error instanceof Error ? error.message : 'Unknown error'}`));
260→      }
261→    }
262→  }
263→
264→  // After V6 auto force-sync: all re-synced sessions have updated message counts.
265→  // Any existing insights were generated from the old (inflated) counts — show advisory.
266→  if (v6JustApplied && !options.quiet && totalSyncedCount > 0) {
267→    log(chalk.dim(`\n  i ${totalSyncedCount} sessions have updated message counts. Existing insights may reflect old data.`));
268→    log(chalk.dim(`    Run 'code-insights reflect backfill' to regenerate (uses LLM API credits).`));
269→
270→    trackEvent('migration_v6_resync', {
271→      sessions_recalculated: totalSyncedCount,
272→      insight_count: totalSyncedCount,
273→    });
274→  }
275→
276→  // Save sync state
277→  syncState.lastSync = new Date().toISOString();
278→  saveSyncState(syncState);
279→
280→  return {
281→    syncedCount: totalSyncedCount,
282→    messageCount: totalMessageCount,
283→    errorCount: totalErrorCount,
284→    updatedExistingCount: totalUpdatedExisting,
285→    sessionsByProvider,
286→  };
287→}
288→
289→/**
290→ * Sync AI coding sessions to local SQLite database
291→ */
292→export async function syncCommand(options: SyncOptions = {}): Promise<void> {
293→  const log = options.quiet ? () => {} : console.log.bind(console);
294→  const startTime = Date.now();
295→
296→  try {
297→    const result = await runSync(options);
298→    const duration_ms = Date.now() - startTime;
299→
300→    // Identify user now that DB is open (updates total_sessions person property)
301→    void identifyUser();
302→
303→    // Summary (only if not quiet)
304→    if (result.syncedCount === 0 && result.errorCount === 0) {
305→      log(chalk.green('\n  Already up to date!'));
306→      trackEvent('cli_sync', {
307→        duration_ms,
308→        sessions_synced: 0,
309→        sessions_by_provider: result.sessionsByProvider,
310→        errors: 0,
311→        source_filter: options.source ?? null,
312→        success: true,
313→      });
314→      return;
315→    }
316→    log(chalk.cyan('\n  Sync Summary'));
317→    const newCount = Math.max(result.syncedCount - result.updatedExistingCount, 0);
318→    log(chalk.white(`  Sessions new: ${newCount}`));
319→    if (result.updatedExistingCount > 0) {
320→      log(chalk.white(`  Sessions updated: ${result.updatedExistingCount}`));
321→    }
322→    log(chalk.white(`  Messages synced: ${result.messageCount}`));
323→    if (result.errorCount > 0) {
324→      log(chalk.red(`  Errors: ${result.errorCount}`));
325→    }
326→    log(chalk.green('\n  Sync complete!'));
327→    trackEvent('cli_sync', {
328→      duration_ms,
329→      sessions_synced: result.syncedCount,
330→      sessions_by_provider: result.sessionsByProvider,
331→      errors: result.errorCount,
332→      source_filter: options.source ?? null,
333→      success: true,
334→    });
335→  } catch (error) {
336→    const duration_ms = Date.now() - startTime;
337→    const { error_type, error_message } = classifyError(error);
338→    trackEvent('cli_sync', {
339→      duration_ms,
340→      sessions_synced: 0,
341→      sessions_by_provider: {},
342→      errors: 1,
343→      source_filter: options.source ?? null,
344→      success: false,
345→      error_type,
346→      error_message,
347→    });
348→    captureError(error, { command: 'sync', error_type, source_filter: options.source ?? null });
349→    if (!options.quiet) {
350→      console.error(chalk.red(error instanceof Error ? error.message : 'Sync failed'));
351→    }
352→    process.exit(1);
353→  }
354→}
355→
356→/**
357→ * Filter files to only those that need syncing
358→ */
359→function filterFilesToSync(files: string[], syncState: SyncState, force?: boolean): string[] {
360→  if (force) return files;
361→
362→  return files.filter((filePath) => {
363→    const { realPath, sessionFragment } = splitVirtualPath(filePath);
364→    const stat = fs.statSync(realPath);
365→    const lastModified = stat.mtime.toISOString();
366→    const fileState = syncState.files[realPath];
367→
368→    // If file was never synced, sync it
369→    if (!fileState) return true;
370→
371→    if (sessionFragment) {
372→      // Virtual path (multi-session DB).
373→      // If the DB file changed, re-sync all sessions from it.
374→      if (fileState.lastModified !== lastModified) return true;
375→
376→      // Otherwise only sync sessions we haven't seen yet.
377→      if (fileState.syncedSessionIds) {
378→        return !fileState.syncedSessionIds.includes(sessionFragment);
379→      }
380→
381→      // Virtual path but no syncedSessionIds tracked yet — needs sync
382→      return true;
383→    }
384→
385→    // For regular files, check if modified since last sync
386→    return fileState.lastModified !== lastModified;
387→  });
388→}
389→
390→/**
391→ * Update sync state for a file
392→ */
393→function updateSyncState(state: SyncState, filePath: string, sessionId: string): void {
394→  const { realPath, sessionFragment } = splitVirtualPath(filePath);
395→  const stat = fs.statSync(realPath);
396→
397→  if (sessionFragment) {
398→    // Virtual path: track the session fragment in syncedSessionIds
399→    const existing = state.files[realPath];
400→    const syncedIds = existing?.syncedSessionIds || [];
401→    if (!syncedIds.includes(sessionFragment)) {
402→      syncedIds.push(sessionFragment);
403→    }
404→    state.files[realPath] = {
405→      lastModified: stat.mtime.toISOString(),
406→      lastSyncedLine: 0,
407→      sessionId,
408→      syncedSessionIds: syncedIds,
409→    };
410→  } else {
411→    // Regular file path
412→    state.files[realPath] = {
413→      lastModified: stat.mtime.toISOString(),
414→      lastSyncedLine: 0,
415→      sessionId,
416→    };
417→  }
418→}
419→
420→interface TrivialSession {
421→  id: string;
422→  title: string | null;
423→  project_name: string;
424→  message_count: number;
425→}
426→
427→/**
428→ * Return sessions with ≤2 messages that are not yet soft-deleted.
429→ * Used to preview what `sync prune` will affect before asking for confirmation.
430→ */
431→export function getTrivialSessions(): TrivialSession[] {
432→  const db = getDb();
433→  return db.prepare(`
434→    SELECT id, title, project_name, message_count
435→    FROM sessions
436→    WHERE message_count <= 2 AND deleted_at IS NULL
437→    ORDER BY started_at DESC
438→  `).all() as TrivialSession[];
439→}
440→
441→/**
442→ * Soft-delete sessions with ≤2 messages — likely abandoned prompts with no useful content.
443→ * Unlike --force sync which resurrects deleted sessions, prune is a deliberate cleanup action.
444→ * Accepts the session IDs to delete so the caller can preview before executing.
445→ */
446→export function pruneTrivialSessions(ids: string[]): { deleted: number } {
447→  if (ids.length === 0) return { deleted: 0 };
448→  const db = getDb();
449→  const placeholders = ids.map(() => '?').join(', ');
450→  const result = db.prepare(`
451→    UPDATE sessions
452→    SET deleted_at = datetime('now')
453→    WHERE id IN (${placeholders}) AND deleted_at IS NULL
454→  `).run(...ids);
455→  return { deleted: result.changes };
456→}
