  1→import { resolve, dirname } from 'path';
  2→import { fileURLToPath, pathToFileURL } from 'url';
  3→import { existsSync } from 'fs';
  4→import chalk from 'chalk';
  5→import ora from 'ora';
  6→import net from 'net';
  7→import { trackEvent, captureError, classifyError } from '../utils/telemetry.js';
  8→import { printBanner } from '../utils/banner.js';
  9→
 10→interface DashboardOptions {
 11→  port: string;
 12→  open: boolean;
 13→}
 14→
 15→/**
 16→ * Check if a port is already in use.
 17→ * - Checks only EADDRINUSE, not other errors (e.g. EACCES for privileged ports).
 18→ * - Waits for the test socket to fully close before resolving, avoiding a TOCTOU
 19→ *   race where the real server tries to bind before the OS releases the port.
 20→ */
 21→function isPortInUse(port: number): Promise<boolean> {
 22→  return new Promise((resolvePromise) => {
 23→    const server = net.createServer();
 24→    server.once('error', (err: NodeJS.ErrnoException) => {
 25→      server.close();
 26→      resolvePromise(err.code === 'EADDRINUSE');
 27→    });
 28→    server.once('listening', () => {
 29→      // Wait for close callback before resolving so the OS fully releases the port
 30→      server.close(() => resolvePromise(false));
 31→    });
 32→    server.listen(port, '127.0.0.1');
 33→  });
 34→}
 35→
 36→/**
 37→ * Start the Code Insights local dashboard server.
 38→ *
 39→ * Loads server/dist/index.js by file URL rather than package name to avoid a
 40→ * circular workspace dependency (server depends on @code-insights/cli, so CLI
 41→ * cannot list @code-insights/server as a build-time dep). pathToFileURL ensures
 42→ * the import works on Windows where absolute paths like C:\... are not valid
 43→ * ESM import specifiers.
 44→ */
 45→export async function dashboardCommand(options: DashboardOptions): Promise<void> {
 46→  const port = parseInt(options.port, 10);
 47→
 48→  if (isNaN(port) || port < 1 || port > 65535) {
 49→    console.error(chalk.red(`  Invalid port: ${options.port}`));
 50→    process.exit(1);
 51→  }
 52→
 53→  const inUse = await isPortInUse(port);
 54→  if (inUse) {
 55→    console.error(chalk.red(`  Port ${port} is already in use.`));
 56→    console.error(chalk.dim(`  Try: code-insights dashboard --port <number>`));
 57→    process.exit(1);
 58→  }
 59→
 60→  const spinner = ora('Starting Code Insights dashboard...').start();
 61→
 62→  try {
 63→    const __filename = fileURLToPath(import.meta.url);
 64→    const __dirname = dirname(__filename);
 65→
 66→    // cli/dist/commands/dashboard.js -> workspace root is 3 levels up
 67→    const workspaceRoot = resolve(__dirname, '..', '..', '..');
 68→    // cli/dist/commands/dashboard.js -> CLI package root is 2 levels up
 69→    const cliRoot = resolve(__dirname, '..', '..');
 70→
 71→    // Try workspace layout first (dev), then npm-installed layout (production)
 72→    let serverEntryPath = resolve(workspaceRoot, 'server', 'dist', 'index.js');
 73→    let staticDir = resolve(workspaceRoot, 'dashboard', 'dist');
 74→
 75→    if (!existsSync(serverEntryPath)) {
 76→      serverEntryPath = resolve(cliRoot, 'server-dist', 'index.js');
 77→      staticDir = resolve(cliRoot, 'dashboard-dist');
 78→    }
 79→
 80→    if (!existsSync(serverEntryPath)) {
 81→      spinner.fail('Dashboard server not found.');
 82→      console.error(chalk.dim(
 83→        '  Run from a workspace checkout: pnpm install && pnpm build\n' +
 84→        '  Or install globally: npm install -g @code-insights/cli\n' +
 85→        '  See: https://github.com/melagiri/code-insights#development',
 86→      ));
 87→      process.exit(1);
 88→    }
 89→
 90→    // Use pathToFileURL so the import specifier is valid on all platforms,
 91→    // including Windows where resolve() returns C:\...\index.js.
 92→    type ServerModule = { startServer: (opts: { port: number; staticDir: string; openBrowser: boolean }) => Promise<void> };
 93→    const { startServer } = await import(pathToFileURL(serverEntryPath).href) as ServerModule;
 94→
 95→    spinner.stop();
 96→    printBanner();
 97→    console.log(chalk.white(`  Dashboard:  `) + chalk.cyan.underline(`http://localhost:${port}`));
 98→    console.log(chalk.dim(`  Press Ctrl+C to stop`));
 99→    console.log('');
100→
101→    trackEvent('cli_dashboard', { port: port, success: true });
102→    await startServer({ port, staticDir, openBrowser: options.open });
103→  } catch (err) {
104→    spinner.fail('Failed to start dashboard server.');
105→    console.error(chalk.red(err instanceof Error ? err.message : String(err)));
106→    const { error_type, error_message } = classifyError(err);
107→    trackEvent('cli_dashboard', { success: false, error_type, error_message });
108→    captureError(err, { command: 'dashboard', error_type });
109→    process.exit(1);
110→  }
111→}
