  1→import * as fs from 'fs';
  2→import * as path from 'path';
  3→import * as os from 'os';
  4→import type { ClaudeInsightConfig, SyncState } from '../types.js';
  5→
  6→const CONFIG_DIR = path.join(os.homedir(), '.code-insights');
  7→const CONFIG_FILE = path.join(CONFIG_DIR, 'config.json');
  8→const SYNC_STATE_FILE = path.join(CONFIG_DIR, 'sync-state.json');
  9→
 10→/**
 11→ * Ensure config directory exists
 12→ */
 13→export function ensureConfigDir(): void {
 14→  if (!fs.existsSync(CONFIG_DIR)) {
 15→    fs.mkdirSync(CONFIG_DIR, { recursive: true, mode: 0o700 });
 16→  }
 17→}
 18→
 19→/**
 20→ * Load configuration from file
 21→ */
 22→export function loadConfig(): ClaudeInsightConfig | null {
 23→  try {
 24→    if (!fs.existsSync(CONFIG_FILE)) {
 25→      return null;
 26→    }
 27→    const content = fs.readFileSync(CONFIG_FILE, 'utf-8');
 28→    return JSON.parse(content) as ClaudeInsightConfig;
 29→  } catch {
 30→    return null;
 31→  }
 32→}
 33→
 34→/**
 35→ * Save configuration to file.
 36→ *
 37→ * Only the known fields of ClaudeInsightConfig are written. This strips any
 38→ * stale keys (e.g. `firebase`, `webConfig`, `dataSource`, `dashboardUrl`)
 39→ * that may have been persisted by earlier versions of the CLI, so they don't
 40→ * accumulate in the config file across upgrades.
 41→ */
 42→export function saveConfig(config: ClaudeInsightConfig): void {
 43→  ensureConfigDir();
 44→  const clean: ClaudeInsightConfig = {
 45→    sync: config.sync,
 46→  };
 47→  if (config.dashboard !== undefined) {
 48→    clean.dashboard = {
 49→      ...(config.dashboard.port !== undefined ? { port: config.dashboard.port } : {}),
 50→      ...(config.dashboard.llm !== undefined ? { llm: config.dashboard.llm } : {}),
 51→    };
 52→  }
 53→  if (config.telemetry !== undefined) {
 54→    clean.telemetry = config.telemetry;
 55→  }
 56→  fs.writeFileSync(CONFIG_FILE, JSON.stringify(clean, null, 2), { mode: 0o600 });
 57→}
 58→
 59→/**
 60→ * Load sync state
 61→ */
 62→export function loadSyncState(): SyncState {
 63→  try {
 64→    if (!fs.existsSync(SYNC_STATE_FILE)) {
 65→      return { lastSync: '', files: {} };
 66→    }
 67→    const content = fs.readFileSync(SYNC_STATE_FILE, 'utf-8');
 68→    return JSON.parse(content) as SyncState;
 69→  } catch {
 70→    return { lastSync: '', files: {} };
 71→  }
 72→}
 73→
 74→/**
 75→ * Save sync state
 76→ */
 77→export function saveSyncState(state: SyncState): void {
 78→  ensureConfigDir();
 79→  fs.writeFileSync(SYNC_STATE_FILE, JSON.stringify(state, null, 2), { mode: 0o600 });
 80→}
