 1→import { getSessionTitle, formatDurationMinutes } from '@/lib/utils';
 2→import type { Insight, Session } from '@/lib/types';
 3→
 4→/**
 5→ * Trigger a markdown file download for a session.
 6→ * Toast notification is the caller's responsibility (UI concern).
 7→ */
 8→export function exportSession(
 9→  session: Session,
10→  insights: Insight[],
11→  summaryText: string | null | undefined,
12→  format: 'plain' | 'obsidian' | 'notion'
13→): void {
14→  const title = getSessionTitle(session);
15→  const startedAt = new Date(session.started_at);
16→  const endedAt = new Date(session.ended_at);
17→  const durationMinutes = Math.round((endedAt.getTime() - startedAt.getTime()) / 60000);
18→  const dateStr = startedAt.toISOString().slice(0, 10);
19→  const lines: string[] = [];
20→
21→  if (format === 'obsidian') {
22→    lines.push(`# ${title}`, '', `> [!info]`);
23→    lines.push(
24→      `> Date: ${dateStr}  `,
25→      `> Duration: ${formatDurationMinutes(durationMinutes)}  `,
26→      `> Project: ${session.project_name}`
27→    );
28→  } else {
29→    lines.push(
30→      `# ${title}`,
31→      '',
32→      `**Date:** ${dateStr}  `,
33→      `**Duration:** ${formatDurationMinutes(durationMinutes)}  `,
34→      `**Project:** ${session.project_name}`
35→    );
36→  }
37→
38→  if (summaryText) {
39→    lines.push('', '## Summary', '', summaryText);
40→  }
41→  if (insights.length > 0) {
42→    lines.push('', '## Insights');
43→    for (const insight of insights.filter((i) => i.type !== 'summary')) {
44→      lines.push('', `### ${insight.title} (${insight.type})`, '', insight.content);
45→    }
46→  }
47→
48→  const content = lines.join('\n');
49→  const projectSlug = session.project_name.toLowerCase().replace(/[^a-z0-9]+/g, '-');
50→  const filename = `session-${projectSlug}-${dateStr}.md`;
51→  const blob = new Blob([content], { type: 'text/markdown' });
52→  const url = URL.createObjectURL(blob);
53→  const a = document.createElement('a');
54→  a.href = url;
55→  a.download = filename;
56→  document.body.appendChild(a);
57→  a.click();
58→  document.body.removeChild(a);
59→  URL.revokeObjectURL(url);
60→}
