 27→/**
 28→ * Create the Hono app with all API routes mounted.
 29→ * Does NOT add static file serving or call serve() — that's startServer's job.
 30→ * Exported so tests can use app.request() without starting a real server.
 31→ */
 32→export function createApp(): Hono {
 33→  const app = new Hono();
 34→
 35→  // Global error handler — prevents stack trace leakage to clients.
 36→  // Detects malformed JSON bodies (SyntaxError) and returns 400 instead of 500.
 37→  app.onError((err, c) => {
 38→    if (err instanceof SyntaxError && err.message.includes('JSON')) {
 39→      return c.json({ error: 'Invalid JSON in request body' }, 400);
 40→    }
 41→    console.error(err);
 42→    return c.json({ error: 'Internal server error' }, 500);
 43→  });
 44→
 45→  // API routes — all under /api
 46→  app.route('/api/projects', projectsRouter);
 47→  app.route('/api/sessions', sessionsRouter);
 48→  app.route('/api/messages', messagesRouter);
 49→  app.route('/api/insights', insightsRouter);
 50→  app.route('/api/analysis', analysisRouter);
 51→  app.route('/api/analytics', analyticsRouter);
 52→  app.route('/api/config', configRouter);
 53→  app.route('/api/export', exportRouter);
 54→  app.route('/api/telemetry', telemetryRouter);
