 1→import Database from 'better-sqlite3';
 2→import { join } from 'path';
 3→import { homedir } from 'os';
 4→import { mkdirSync, existsSync } from 'fs';
 5→import { runMigrations, type MigrationResult } from './migrate.js';
 6→
 7→const DB_DIR = join(homedir(), '.code-insights');
 8→const DB_PATH = join(DB_DIR, 'data.db');
 9→
10→let _db: Database.Database | null = null;
11→let _migrationResult: MigrationResult | null = null;
12→
13→/**
14→ * Get (or initialize) the singleton SQLite database instance.
15→ * WAL mode is enabled for concurrent reads during CLI sync.
16→ * Migrations run automatically on first call.
17→ */
18→export function getDb(): Database.Database {
19→  if (_db) return _db;
20→
21→  if (!existsSync(DB_DIR)) {
22→    mkdirSync(DB_DIR, { recursive: true, mode: 0o700 });
23→  }
24→
25→  const db = new Database(DB_PATH);
26→
27→  // WAL mode: allows concurrent reads while CLI writes
28→  db.pragma('journal_mode = WAL');
29→  // Wait up to 5s if another writer holds the lock (e.g., dashboard writing insights)
30→  db.pragma('busy_timeout = 5000');
31→  // Foreign key enforcement
32→  db.pragma('foreign_keys = ON');
33→
34→  _migrationResult = runMigrations(db);
35→
36→  _db = db;
37→
38→  // Ensure WAL checkpoint runs on process exit so no data is left in the WAL file.
39→  // Registered here (on first open) so it fires whether process exits normally or
40→  // via an unhandled exception that reaches the exit handler.
41→  process.on('exit', () => {
42→    closeDb();
43→  });
44→
45→  return _db;
46→}
47→
48→/**
49→ * Get the migration result from the last getDb() call.
50→ * Returns null if the DB has not been initialized yet.
51→ * Used by sync.ts to detect V6 migration and trigger auto force-sync.
52→ */
53→export function getMigrationResult(): MigrationResult | null {
54→  return _migrationResult;
55→}
56→
57→/**
58→ * Close the database connection. Used in tests and graceful shutdown.
59→ * Also called by the process 'exit' handler to ensure WAL checkpointing.
60→ */
61→export function closeDb(): void {
62→  if (_db) {
63→    _db.close();
64→    _db = null;
65→  }
66→  _migrationResult = null;
67→}
68→
69→/**
70→ * Get the database file path.
71→ */
72→export function getDbPath(): string {
73→  return DB_PATH;
74→}
