 7→
 8→/**
 9→ * Claude Code session provider.
10→ * Discovers and parses JSONL session files from ~/.claude/projects/
11→ */
12→export class ClaudeCodeProvider implements SessionProvider {
13→  getProviderName(): string {
14→    return 'claude-code';
15→  }
16→
17→  async discover(options?: { projectFilter?: string }): Promise<string[]> {
18→    const baseDir = getClaudeDir();
19→
20→    if (!fs.existsSync(baseDir)) {
21→      return [];
22→    }
23→
24→    return discoverJsonlFiles(baseDir, options?.projectFilter);
25→  }
26→
27→  async parse(filePath: string): Promise<ParsedSession | null> {
28→    const session = await parseJsonlFile(filePath);
29→    if (session) {
30→      session.sourceTool = 'claude-code';
31→    }
32→    return session;
33→  }
34→}
35→
36→/**
37→ * Discover all JSONL files in Claude directory
38→ */
39→function discoverJsonlFiles(baseDir: string, projectFilter?: string): string[] {
40→  const files: string[] = [];
41→
42→  const projectDirs = fs.readdirSync(baseDir);
43→  for (const projectDir of projectDirs) {
44→    // Skip hidden files and non-directories
45→    if (projectDir.startsWith('.')) continue;
46→
47→    const projectPath = path.join(baseDir, projectDir);
48→    const stat = fs.statSync(projectPath);
49→    if (!stat.isDirectory()) continue;
50→
51→    // Apply project filter if specified
52→    if (projectFilter && !projectDir.toLowerCase().includes(projectFilter.toLowerCase())) {
53→      continue;
54→    }
55→
56→    // Find JSONL files in project directory
57→    const projectFiles = fs.readdirSync(projectPath);
58→    for (const file of projectFiles) {
59→      if (file.endsWith('.jsonl')) {
60→        files.push(path.join(projectPath, file));
61→      }
62→    }
63→
64→    // Also check subagents directory
65→    const subagentsDir = path.join(projectPath, 'subagents');
66→    if (fs.existsSync(subagentsDir)) {
67→      const subagentFiles = fs.readdirSync(subagentsDir);
68→      for (const file of subagentFiles) {
69→        if (file.endsWith('.jsonl')) {
70→          files.push(path.join(subagentsDir, file));
71→        }
72→      }
73→    }
74→  }
75→
76→  return files;
77→}
