 10→/**
 11→ * Cursor IDE session provider.
 12→ * Discovers and parses sessions from Cursor's SQLite databases.
 13→ *
 14→ * Cursor stores composer conversations in state.vscdb files (SQLite).
 15→ * One DB can contain multiple sessions (composers), so discover() returns
 16→ * virtual paths in the format `state.vscdb#<composerId>` — one per session.
 17→ * This keeps the SessionProvider interface unchanged (1 path = 1 session).
 18→ */
 19→export class CursorProvider implements SessionProvider {
 20→  getProviderName(): string {
 21→    return 'cursor';
 22→  }
 23→
 24→  /**
 25→   * Discover Cursor composer sessions.
 26→   * Returns virtual paths: `<dbPath>#<composerId>` — one per session.
 27→   */
 28→  async discover(options?: { projectFilter?: string }): Promise<string[]> {
 29→    const cursorDataDir = getCursorDataDir();
 30→    if (!cursorDataDir) {
 31→      return [];
 32→    }
 33→
 34→    const dbPaths: string[] = [];
 35→
 36→    // 1. Check workspace storage databases
 37→    const workspaceStorageDir = path.join(cursorDataDir, 'workspaceStorage');
 38→    if (fs.existsSync(workspaceStorageDir)) {
 39→      const entries = fs.readdirSync(workspaceStorageDir);
 40→      for (const entry of entries) {
 41→        const wsDir = path.join(workspaceStorageDir, entry);
 42→        if (!fs.statSync(wsDir).isDirectory()) continue;
 43→
 44→        const dbPath = path.join(wsDir, 'state.vscdb');
 45→        if (!fs.existsSync(dbPath)) continue;
 46→
 47→        // Apply project filter if specified
 48→        if (options?.projectFilter) {
 49→          const projectPath = resolveWorkspacePath(wsDir);
 50→          if (projectPath && !projectPath.toLowerCase().includes(options.projectFilter.toLowerCase())) {
 51→            continue;
 52→          }
 53→        }
 54→
 55→        dbPaths.push(dbPath);
 56→      }
 57→    }
 58→
 59→    // 2. Check global storage database
 60→    const globalDbPath = path.join(cursorDataDir, 'globalStorage', 'state.vscdb');
 61→    if (fs.existsSync(globalDbPath)) {
 62→      dbPaths.push(globalDbPath);
 63→    }
 64→
 65→    // Expand each DB path into virtual paths — one per composer session
 66→    const virtualPaths: string[] = [];
 67→
 68→    for (const dbPath of dbPaths) {
 69→      const composerIds = getComposerIds(dbPath);
 70→      for (const composerId of composerIds) {
 71→        virtualPaths.push(`${dbPath}#${composerId}`);
 72→      }
 73→    }
 74→
 75→    return virtualPaths;
 76→  }
 77→
 78→  /**
 79→   * Parse a single Cursor session from a virtual path.
 80→   * Virtual path format: `<dbPath>#<composerId>`
 81→   */
 82→  async parse(virtualPath: string): Promise<ParsedSession | null> {
 83→    const hashIndex = virtualPath.lastIndexOf('#');
 84→    if (hashIndex === -1) return null;
 85→
 86→    const dbPath = virtualPath.slice(0, hashIndex);
 87→    const composerId = virtualPath.slice(hashIndex + 1);
 88→    if (!composerId) return null;
 89→
 90→    return parseCursorSession(dbPath, composerId);
 91→  }
 92→}
