 1→import * as fs from 'fs';
 2→import * as path from 'path';
 3→import * as os from 'os';
 4→import type { SessionProvider } from './types.js';
 5→import type { ParsedSession, ParsedMessage, ToolCall, ToolResult, SessionUsage, MessageUsage } from '../types.js';
 6→import { generateTitle, detectSessionCharacter } from '../parser/titles.js';
 7→
 8→/**
 9→ * OpenAI Codex CLI session provider.
10→ * Discovers and parses rollout files from ~/.codex/sessions/
11→ *
12→ * Supports two formats:
13→ *   Format A: JSONL (v0.104.0+, 2026) — envelope/payload structure with response_item/event_msg
14→ *   Format B: Single JSON object (pre-2025) — bare items array with no envelope
15→ */
16→export class CodexProvider implements SessionProvider {
17→  getProviderName(): string {
18→    return 'codex-cli';
19→  }
20→
21→  async discover(options?: { projectFilter?: string }): Promise<string[]> {
22→    const codexHome = getCodexHome();
23→    if (!codexHome) return [];
24→
25→    const files: string[] = [];
26→
27→    // Walk sessions/ and archived_sessions/ directories
28→    for (const subdir of ['sessions', 'archived_sessions']) {
29→      const sessionsDir = path.join(codexHome, subdir);
30→      if (!fs.existsSync(sessionsDir)) continue;
31→      collectRolloutFiles(sessionsDir, files);
32→    }
33→
34→    // Apply project filter if specified (filter by cwd from session_meta)
35→    if (options?.projectFilter) {
36→      return filterByProject(files, options.projectFilter);
37→    }
38→
39→    return files;
40→  }
41→
42→  async parse(filePath: string): Promise<ParsedSession | null> {
43→    return parseCodexSession(filePath);
44→  }
45→}
46→
47→// ---------------------------------------------------------------------------
48→// Discovery helpers
49→// ---------------------------------------------------------------------------
50→
51→function getCodexHome(): string | null {
52→  const envHome = process.env.CODEX_HOME;
53→  if (envHome && fs.existsSync(envHome)) return envHome;
54→
55→  const home = os.homedir();
56→  const defaultDir = path.join(home, '.codex');
57→  return fs.existsSync(defaultDir) ? defaultDir : null;
58→}
59→
60→/**
61→ * Recursively collect rollout-*.jsonl and rollout-*.json files from date-organized directories.
62→ * Format A lives at: sessions/YYYY/MM/DD/rollout-<timestamp>-<uuid>.jsonl
63→ * Format B lives at: sessions/rollout-<date>-<uuid>.json (flat)
64→ */
65→function collectRolloutFiles(dir: string, files: string[], depth = 0): void {
66→  if (depth > 10) return; // Guard against symlink loops
67→  const entries = fs.readdirSync(dir, { withFileTypes: true });
68→  for (const entry of entries) {
69→    const fullPath = path.join(dir, entry.name);
70→    if (entry.isDirectory()) {
71→      collectRolloutFiles(fullPath, files, depth + 1);
72→    } else if (
73→      (entry.name.startsWith('rollout-') && entry.name.endsWith('.jsonl')) ||
74→      (entry.name.startsWith('rollout-') && entry.name.endsWith('.json'))
75→    ) {
76→      files.push(fullPath);
77→    }
78→  }
79→}
