#!/usr/bin/env node

import { readFileSync } from 'fs';
import { Command } from 'commander';
import { initCommand } from './commands/init.js';
import { syncCommand, getTrivialSessions, pruneTrivialSessions } from './commands/sync.js';
import { statusCommand } from './commands/status.js';
import { installHookCommand, uninstallHookCommand } from './commands/install-hook.js';
import { openCommand } from './commands/open.js';
import { dashboardCommand } from './commands/dashboard.js';
import { resetCommand } from './commands/reset.js';
import { statsCommand } from './commands/stats/index.js';
import { configCommand } from './commands/config.js';
import { telemetryCommand } from './commands/telemetry.js';
import { reflectCommand } from './commands/reflect.js';
import { showTelemetryNoticeIfNeeded } from './utils/telemetry.js';

const pkg = JSON.parse(readFileSync(new URL('../package.json', import.meta.url), 'utf-8'));

const program = new Command();

program
  .name('code-insights')
  .description('AI coding session analytics — sync, stats, and insights')
  .version(pkg.version);

program
  .command('init')
  .description('Set up Code Insights (initializes local database)')
  .action(initCommand);

const syncCmd = program
  .command('sync')
  .description('Sync AI coding sessions to local SQLite database')
  .option('-f, --force', 'Force re-sync all sessions (also restores hidden sessions)')
  .option('-p, --project <name>', 'Only sync sessions from a specific project')
  .option('-s, --source <name>', 'Only sync sessions from a specific tool (e.g., claude-code, cursor)')
  .option('--dry-run', 'Show what would be synced without making changes')
  .option('-q, --quiet', 'Suppress output (useful for hooks)')
  .option('-v, --verbose', 'Show diagnostic warnings from providers')
  .option('--regenerate-titles', 'Regenerate titles for all sessions')
  .action(syncCommand);

syncCmd
  .command('prune')
  .description('Soft-delete sessions with ≤2 messages (trivial abandoned sessions)')
  .action(async () => {
    const chalk = (await import('chalk')).default;
    const { default: inquirer } = await import('inquirer');
    console.log(chalk.cyan('\n  Code Insights — Prune\n'));

    const sessions = getTrivialSessions();
    if (sessions.length === 0) {
      console.log(chalk.green('  No trivial sessions found. Nothing to prune.'));
      return;
    }

    console.log(chalk.white(`  Found ${sessions.length} session${sessions.length !== 1 ? 's' : ''} with ≤2 messages:\n`));
    for (const s of sessions) {
      const label = s.title ?? chalk.dim('(no title)');
      console.log(`  ${chalk.dim('·')} ${label} ${chalk.dim(`[${s.project_name}, ${s.message_count} msg]`)}`);
    }
    console.log('');

    const { confirmed } = await inquirer.prompt<{ confirmed: boolean }>([
      {
        type: 'confirm',
        name: 'confirmed',
        message: `Soft-delete these ${sessions.length} session${sessions.length !== 1 ? 's' : ''}? (Restorable with sync --force)`,
        default: false,
      },
    ]);

    if (!confirmed) {
      console.log(chalk.yellow('\n  Cancelled. No sessions were hidden.'));
      return;
    }

    const { deleted } = pruneTrivialSessions(sessions.map((s) => s.id));
    console.log(chalk.green(`\n  Hidden ${deleted} session${deleted !== 1 ? 's' : ''}.`));
    console.log(chalk.dim('  Use code-insights sync --force to restore hidden sessions.'));
  });

program
  .command('status')
  .description('Show Code Insights status and statistics')
  .action(statusCommand);

program
  .command('install-hook')
  .description('Install Claude Code hook for automatic sync')
  .action(installHookCommand);

program
  .command('uninstall-hook')
  .description('Remove Claude Code hook')
  .action(uninstallHookCommand);

program
  .command('open')
  .description('Open the local dashboard in your browser')
  .option('--project', 'Open filtered to the current project')
  .action(openCommand);

program
  .command('dashboard')
  .description('Start the Code Insights dashboard server and open in browser')
  .option('-p, --port <number>', 'Port number', String(7890))
  .option('--no-open', 'Do not open browser automatically')
  .option('--no-sync', 'Skip automatic session sync before starting')
  .action(dashboardCommand);

program.addCommand(resetCommand);
program.addCommand(statsCommand);
program.addCommand(configCommand);
program.addCommand(telemetryCommand);
program.addCommand(reflectCommand);

// Default action: running `code-insights` with no arguments opens the dashboard.
// Dashboard auto-syncs sessions first, giving "1 command to value" on first run.
program.action(async () => {
  await dashboardCommand({ port: '7890', open: true, sync: true });
});

// Show one-time telemetry disclosure before any command runs
showTelemetryNoticeIfNeeded();

program.parse();

import { resolve, dirname } from 'path';
import { fileURLToPath, pathToFileURL } from 'url';
import { existsSync } from 'fs';
import chalk from 'chalk';
import ora from 'ora';
import net from 'net';
import { trackEvent, identifyUser, captureError, classifyError } from '../utils/telemetry.js';
import { printBanner } from '../utils/banner.js';
import { runSync } from './sync.js';

interface DashboardOptions {
  port: string;
  open: boolean;
  // Commander's --no-sync flag sets sync=false; default (no flag) is true
  sync?: boolean;
}

/**
 * Check if a port is already in use.
 * - Checks only EADDRINUSE, not other errors (e.g. EACCES for privileged ports).
 * - Waits for the test socket to fully close before resolving, avoiding a TOCTOU
 *   race where the real server tries to bind before the OS releases the port.
 */
function isPortInUse(port: number): Promise<boolean> {
  return new Promise((resolvePromise) => {
    const server = net.createServer();
    server.once('error', (err: NodeJS.ErrnoException) => {
      server.close();
      resolvePromise(err.code === 'EADDRINUSE');
    });
    server.once('listening', () => {
      // Wait for close callback before resolving so the OS fully releases the port
      server.close(() => resolvePromise(false));
    });
    server.listen(port, '127.0.0.1');
  });
}

/**
 * Start the Code Insights local dashboard server.
 *
 * Loads server/dist/index.js by file URL rather than package name to avoid a
 * circular workspace dependency (server depends on @code-insights/cli, so CLI
 * cannot list @code-insights/server as a build-time dep). pathToFileURL ensures
 * the import works on Windows where absolute paths like C:\... are not valid
 * ESM import specifiers.
 */
export async function dashboardCommand(options: DashboardOptions): Promise<void> {
  // Auto-sync sessions before starting the dashboard so users see fresh data.
  // Skipped with --no-sync. Uses quiet:false so sync progress is visible on first run.
  if (options.sync !== false) {
    try {
      await runSync({ quiet: false });
      void identifyUser();
    } catch (err) {
      // Sync failure is non-fatal — dashboard still opens with whatever data exists
      console.warn(chalk.yellow(`  Sync warning: ${err instanceof Error ? err.message : String(err)}`));
      console.warn(chalk.dim('  Use --no-sync to skip sync, or run `code-insights sync` separately.'));
    }
  }

  const port = parseInt(options.port, 10);

  if (isNaN(port) || port < 1 || port > 65535) {
    console.error(chalk.red(`  Invalid port: ${options.port}`));
    process.exit(1);
  }

  const inUse = await isPortInUse(port);
  if (inUse) {
    console.error(chalk.red(`  Port ${port} is already in use.`));
    console.error(chalk.dim(`  Try: code-insights dashboard --port <number>`));
    process.exit(1);
  }

  const spinner = ora('Starting Code Insights dashboard...').start();

  try {
    const __filename = fileURLToPath(import.meta.url);
    const __dirname = dirname(__filename);

    // cli/dist/commands/dashboard.js -> workspace root is 3 levels up
    const workspaceRoot = resolve(__dirname, '..', '..', '..');
    // cli/dist/commands/dashboard.js -> CLI package root is 2 levels up
    const cliRoot = resolve(__dirname, '..', '..');

    // Try workspace layout first (dev), then npm-installed layout (production)
    let serverEntryPath = resolve(workspaceRoot, 'server', 'dist', 'index.js');
    let staticDir = resolve(workspaceRoot, 'dashboard', 'dist');

    if (!existsSync(serverEntryPath)) {
      serverEntryPath = resolve(cliRoot, 'server-dist', 'index.js');
      staticDir = resolve(cliRoot, 'dashboard-dist');
    }

    if (!existsSync(serverEntryPath)) {
      spinner.fail('Dashboard server not found.');
      console.error(chalk.dim(
        '  Run from a workspace checkout: pnpm install && pnpm build\n' +
        '  Or install globally: npm install -g @code-insights/cli\n' +
        '  See: https://github.com/melagiri/code-insights#development',
      ));
      process.exit(1);
    }

    // Use pathToFileURL so the import specifier is valid on all platforms,
    // including Windows where resolve() returns C:\...\index.js.
    type ServerModule = { startServer: (opts: { port: number; staticDir: string; openBrowser: boolean }) => Promise<void> };
    const { startServer } = await import(pathToFileURL(serverEntryPath).href) as ServerModule;

    spinner.stop();
    printBanner();
    console.log(chalk.white(`  Dashboard:  `) + chalk.cyan.underline(`http://localhost:${port}`));
    console.log(chalk.dim(`  Press Ctrl+C to stop`));
    console.log('');

    trackEvent('cli_dashboard', { port: port, success: true });
    await startServer({ port, staticDir, openBrowser: options.open });
  } catch (err) {
    spinner.fail('Failed to start dashboard server.');
    console.error(chalk.red(err instanceof Error ? err.message : String(err)));
    const { error_type, error_message } = classifyError(err);
    trackEvent('cli_dashboard', { success: false, error_type, error_message });
    captureError(err, { command: 'dashboard', error_type });
    process.exit(1);
  }
}

import inquirer from 'inquirer';
import chalk from 'chalk';
import { saveConfig, getConfigDir, isConfigured } from '../utils/config.js';
import { getDb } from '../db/client.js';
import { trackEvent, captureError, classifyError } from '../utils/telemetry.js';
import type { ClaudeInsightConfig } from '../types.js';

export interface InitOptions {
  // No options needed for local-first setup
}

/**
 * Initialize Code Insights configuration.
 * Sets up sync preferences and initializes the local SQLite database.
 */
export async function initCommand(_options: InitOptions = {}): Promise<void> {
  console.log(chalk.cyan('\n  Code Insights Setup\n'));

  if (isConfigured()) {
    const { overwrite } = await inquirer.prompt([
      {
        type: 'confirm',
        name: 'overwrite',
        message: 'Configuration already exists. Overwrite?',
        default: false,
      },
    ]);

    if (!overwrite) {
      console.log(chalk.yellow('Setup cancelled.'));
      return;
    }
  }

  // Save minimal config
  const config: ClaudeInsightConfig = {
    sync: { claudeDir: '~/.claude/projects', excludeProjects: [] },
  };
  saveConfig(config);

  // Initialize database (creates schema if first run)
  try {
    getDb();
    console.log(chalk.green('\n  Database initialized at ~/.code-insights/data.db'));
  } catch (error) {
    console.log(chalk.red(`\n  Database initialization failed: ${error instanceof Error ? error.message : 'Unknown error'}`));
    const { error_type, error_message } = classifyError(error);
    trackEvent('cli_init', { success: false, error_type, error_message });
    captureError(error, { command: 'init', error_type });
    process.exit(1);
  }

  console.log(chalk.green('\n  Configuration saved!'));
  console.log(chalk.gray(`  Config location: ${getConfigDir()}/config.json`));

  console.log(chalk.cyan('\n  Setup complete! Next steps:\n'));
  console.log(chalk.white('  1. Sync your sessions:'));
  console.log(chalk.gray('     code-insights sync\n'));
  console.log(chalk.white('  2. View your stats:'));
  console.log(chalk.gray('     code-insights stats\n'));
  console.log(chalk.white('  3. Check today\'s activity:'));
  console.log(chalk.gray('     code-insights stats today\n'));

  trackEvent('cli_init', { success: true });
}

